const body = $input.first().json.body || {};
const query = (body.query || '').toString().trim();
const location = (body.location || '').toString().trim();
if (!query) throw new Error('query is required');
if (query.length > 200) throw new Error('query too long');
if (location.length > 200) throw new Error('location too long');
return [{ json: { query, location } }];

const raw = $input.first().json || {};
const query = $('Validate Input').first().json.query;
const location = $('Validate Input').first().json.location;

if (raw.source === 'error') {
  return [{ json: { fromCache: true, events: [], query, location, scrapeStatus: raw.status || 'ERROR', success: true, count: 0 } }];
}
if (raw.source === 'cache') {
  const events = Array.isArray(raw.events) ? raw.events : [];
  return [{ json: { fromCache: true, events, query, location, success: true, count: events.length } }];
}
return [{ json: { fromCache: false, html: raw.html || '', query, location } }];

