const upstream = $input.first().json || {};
const query = $('Validate Input').first().json.query;
const location = $('Validate Input').first().json.location;
const emptyResp = { success: true, count: 0, fromCache: false, events: [], query, location };

const content = upstream.choices?.[0]?.message?.content || '';
if (!content) return [{ json: emptyResp }];

let parsed;
try { parsed = JSON.parse(content); } catch (e) { return [{ json: emptyResp }]; }

let events = [];
if (Array.isArray(parsed)) events = parsed;
else if (Array.isArray(parsed?.events)) events = parsed.events;

const clean = events.filter(e => e && typeof e === 'object' && typeof e.title === 'string' && e.title.trim().length > 1);
const limited = clean.slice(0, 20).map(e => ({
  title: String(e.title).trim(),
  date: e.date != null ? String(e.date) : null,
  time: e.time != null ? String(e.time) : null,
  venue: e.venue != null ? String(e.venue) : null,
  address: e.address != null ? String(e.address) : null,
  url: e.url != null ? String(e.url) : null,
  source: e.source != null ? String(e.source) : null,
  price: e.price != null ? String(e.price) : null,
  imageUrl: e.imageUrl != null ? String(e.imageUrl) : null,
}));

return [{ json: { success: true, count: limited.length, fromCache: false, events: limited, query, location } }];
